def f(n):
    def factorial(x):
        if x == 0:
            return 1
        else:
            return x * factorial(x-1)

    def sum_of_numbers(x):
        return sum(range(1, x+1))

    return [factorial(i) if i % 2 == 0 else sum_of_numbers(i) for i in range(1, n+1)]

