def minSubArraySum(nums):
    if not nums:
        raise ValueError("nums must be non-empty")

    current_min = nums[0]
    global_min = nums[0]

    for num in nums[1:]:
        current_min = min(num, current_min + num)
        global_min = min(global_min, current_min)

    return global_min

